import dns from "dns";
import mongoose from "mongoose";

/**
 * Checks system DNS configuration and applies a public DNS fallback (Google / Cloudflare)
 * if Node.js (c-ares) is misdetecting the DNS servers as loopback (127.0.0.1) or site-local IPv6 (fec0:...).
 */
const applyDNSPatch = () => {
  try {
    const servers = dns.getServers();
    console.log(`🔍 Current Node.js DNS Servers: ${JSON.stringify(servers)}`);

    // Check if DNS servers only contain loopback IPs or site-local autogenerated IPv6 addresses
    const isLocalOrInvalid = servers.every(
      (server) =>
        server === "127.0.0.1" ||
        server === "::1" ||
        server.toLowerCase().startsWith("fec0:")
    );

    if (isLocalOrInvalid || servers.length === 0) {
      const fallbackDNS = ["8.8.8.8", "1.1.1.1", "8.8.4.4", "1.0.0.1"];
      console.warn(`⚠️ Warning: DNS servers list is local/invalid. Applying DNS patch with: ${fallbackDNS.join(", ")}`);
      dns.setServers(fallbackDNS);
    }
  } catch (err) {
    console.error("⚠️ Error querying/setting DNS servers:", err.message);
  }
};

const connectDB = async () => {
  // Apply DNS configuration patch before initiating database connection
  applyDNSPatch();

  const uri = process.env.MONGODB_URI;
  const fallbackUri = process.env.MONGODB_URI_FALLBACK;

  if (!uri) {
    throw new Error("MONGODB_URI is not defined in .env");
  }

  mongoose.set("strictQuery", true);

  try {
    console.log("🔌 Attempting to connect to MongoDB Atlas...");
    const conn = await mongoose.connect(uri, {
      serverSelectionTimeoutMS: 10000,
      socketTimeoutMS: 45000,
    });

    console.log("✅ MongoDB Connected Successfully");
    console.log(`📦 Host: ${conn.connection.host}`);
    console.log(`🗄️ Database: ${conn.connection.name}`);
  } catch (error) {
    console.error("❌ Primary MongoDB connection failed.");
    console.error(`Error: ${error.message}`);

    if (fallbackUri) {
      console.warn("⚠️ Attempting fallback to non-SRV direct shard connection string...");
      try {
        const conn = await mongoose.connect(fallbackUri, {
          serverSelectionTimeoutMS: 10000,
          socketTimeoutMS: 45000,
        });
        console.log("✅ MongoDB Connected Successfully (via Fallback non-SRV URI)");
        console.log(`📦 Host: ${conn.connection.host}`);
        console.log(`🗄️ Database: ${conn.connection.name}`);
        return;
      } catch (fallbackError) {
        console.error("❌ Fallback MongoDB connection failed.");
        console.error(`Error: ${fallbackError.message}`);
      }
    }

    process.exit(1);
  }
};

export default connectDB;